// Copies compiled CLI dist/ files into site/lib/cli/ for Vercel deployment.
// On Vercel, the repo root is not accessible from site/, so we need local copies.
// Locally, dist/ files are generated by `npm run build` in the root.

const fs = require('fs');
const path = require('path');

const srcDir = path.resolve(__dirname, '../../dist');
const destDir = path.resolve(__dirname, '../lib/cli');

const files = [
  'search.js', 'search.d.ts',
  'artist.js', 'artist.d.ts',
  'track.js', 'track.d.ts',
  'album.js', 'album.d.ts',
  'playlist.js', 'playlist.d.ts',
  'library.js', 'library.d.ts',
  'pagination.js', 'pagination.d.ts',
  'playback.js', 'playback.d.ts',
  'recommend.js', 'recommend.d.ts',
  'mix.js', 'mix.d.ts',
  'history.js', 'history.d.ts',
  'search-history.js', 'search-history.d.ts',
  'saved.js', 'saved.d.ts',
  'share.js', 'share.d.ts',
  'user.js', 'user.d.ts',
  'types.js', 'types.d.ts',
  'auth.js', 'auth.d.ts',
  'session.js', 'session.d.ts',
];

// Create dest directory
fs.mkdirSync(destDir, { recursive: true });

if (!fs.existsSync(srcDir)) {
  console.log('dist/ not found — copying pre-committed lib/cli/ files (Vercel build)');
  process.exit(0);
}

let copied = 0;
for (const file of files) {
  const src = path.join(srcDir, file);
  const dest = path.join(destDir, file);
  if (fs.existsSync(src)) {
    fs.copyFileSync(src, dest);
    copied++;
  }
}

// Copy the curation/ subdir (value-add layer) so the HTTP MCP server can import it.
const curationSrc = path.join(srcDir, 'curation');
const curationDest = path.join(destDir, 'curation');
if (fs.existsSync(curationSrc)) {
  fs.mkdirSync(curationDest, { recursive: true });
  for (const file of fs.readdirSync(curationSrc)) {
    if (file.endsWith('.js') || file.endsWith('.d.ts')) {
      fs.copyFileSync(path.join(curationSrc, file), path.join(curationDest, file));
      copied++;
    }
  }
}

console.log(`Copied ${copied} files from dist/ to lib/cli/`);
